package com.company.snackledger.server;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.http.MediaType;import org.springframework.test.web.servlet.MockMvc;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;@SpringBootTest @AutoConfigureMockMvc class KioskApiTests{@Autowired MockMvc mvc;String key="dev-kiosk-key-change-me";String id="MAIN-OFFICE-KIOSK";@Test void validApiKeyBadgeBarcodeAndDuplicatePurchase()throws Exception{mvc.perform(get("/api/v1/kiosk/users/badge/BADGE100").header("X-Kiosk-Id",id).header("X-Kiosk-Api-Key",key)).andExpect(status().isOk()).andExpect(jsonPath("$.displayName").value("John Smith"));mvc.perform(get("/api/v1/kiosk/items/barcode/100000000001").header("X-Kiosk-Id",id).header("X-Kiosk-Api-Key",key)).andExpect(status().isOk()).andExpect(jsonPath("$.price").value(1.0));String body="{\"requestId\":\"r1\",\"kioskId\":\"MAIN-OFFICE-KIOSK\",\"userId\":1,\"items\":[{\"itemId\":1,\"quantity\":2}]}";mvc.perform(post("/api/v1/kiosk/purchases").header("X-Kiosk-Id",id).header("X-Kiosk-Api-Key",key).contentType(MediaType.APPLICATION_JSON).content(body)).andExpect(status().isOk()).andExpect(jsonPath("$.purchaseTotal").value(2.0));mvc.perform(post("/api/v1/kiosk/purchases").header("X-Kiosk-Id",id).header("X-Kiosk-Api-Key",key).contentType(MediaType.APPLICATION_JSON).content(body)).andExpect(status().isOk()).andExpect(jsonPath("$.purchaseTotal").value(2.0));}@Test void invalidApiKeyRejected()throws Exception{mvc.perform(get("/api/v1/kiosk/users/badge/BADGE100").header("X-Kiosk-Id",id).header("X-Kiosk-Api-Key","bad")).andExpect(status().isUnauthorized());}}
